  @fn atomise(text)  @ 207
      -- Tokenise into atoms with per-pair separators: seps[k] joins atoms[k..k+1]
      -- when they share a line. ' ' between words, '' between CamelCase pieces of
      -- one word, so a re-joined line has no space at the case boundary.
